map "https://example.org/fhir/li-xinyang-interop-r4/StructureMap/ccda-procedure-to-procedure" = "CCDAProcedureToProcedure"

uses "https://example.org/fhir/li-xinyang-interop-r4/StructureDefinition/HITCCCDAEntry" alias CCDAEntry as source
uses "https://example.org/fhir/li-xinyang-interop-r4/StructureDefinition/hitc-canonical-procedure" alias Procedure as target

group CCDAProcedureToProcedure(source src : HITCCCDAEntry, target tgt : Procedure) {
  src.entryId as v -> tgt.identifier.value = copy(v) "identifier";
  src.entryId as v -> tgt.identifier.system = evaluate('https://example.org/fhir/sid/ccda-entry') "identifierSystem";
  src.entryId as v -> tgt.status = evaluate('completed') "completedStatus";
  src.code as v -> tgt.code.coding = copy(v) "procedureCode";
  src.effectiveTime as v -> tgt.performedDateTime = copy(v) "performed";
  src.subjectIdentifier as v -> tgt.subject.identifier.value = copy(v) "patientIdentifier";
}

// Draft and experimental. Reference resolution, source-system extension population, semantic reconciliation, UCUM normalization, temporal normalization, and validation are orchestrated outside this Phase 1 map unless explicitly shown.
